import React, { useState, useEffect } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import { useNetInfo } from '@react-native-community/netinfo';
import * as SecureStore from 'expo-secure-store';
import { randomBytes } from 'react-native-crypto';

const generateSecureToken = () => {
  return randomBytes(32).toString('hex');
};

const storeToken = async (token) => {
  try {
    await SecureStore.setItemAsync('offlineToken', token);
  } catch (error) {
    console.error('Error storing the token', error);
  }
};

const getToken = async () => {
  try {
    const token = await SecureStore.getItemAsync('offlineToken');
    return token;
  } catch (error) {
    console.error('Error retrieving the token', error);
  }
};

const TokenGenerator = () => {
  const [token, setToken] = useState(null);
  const netInfo = useNetInfo();

  useEffect(() => {
    if (!netInfo.isConnected) {
      const newToken = generateSecureToken();
      setToken(newToken);
      storeToken(newToken);
    }
  }, [netInfo.isConnected]);

  const handleShowToken = async () => {
    const storedToken = await getToken();
    Alert.alert('Stored Token', storedToken || 'No token found');
  };

  return (
    <View style={{ padding: 20 }}>
      <Text>Offline Token Generator</Text>
      <Button title="Show Stored Token" onPress={handleShowToken} />
      {token && <Text>Generated Token: {token}</Text>}
    </View>
  );
};

export default TokenGenerator;